from flask import Flask, request, jsonify
from flask_sqlalchemy import SQLAlchemy
from flask_login import LoginManager, login_required, current_user

app = Flask(__name__)
app.config['SQLALCHEMY_DATABASE_URI'] = 'sqlite:///users.db'
db = SQLAlchemy(app)
login_manager = LoginManager(app)

class User(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    email = db.Column(db.String(120), unique=True, nullable=False)
    username = db.Column(db.String(80), unique=True, nullable=False)
    account_type = db.Column(db.String(50), nullable=False)
    credits = db.Column(db.Integer, default=0)
    referral_code = db.Column(db.String(50), unique=True, nullable=True)
    verified_status = db.Column(db.Boolean, default=False)

@login_manager.user_loader
def load_user(user_id):
    return User.query.get(int(user_id))

@app.route('/update_profile', methods=['POST'])
@login_required
def update_profile():
    data = request.json
    user = current_user

    if 'email' in data:
        user.email = data['email']
    if 'username' in data:
        user.username = data['username']
    if 'account_type' in data:
        user.account_type = data['account_type']
    if 'credits' in data:
        user.credits = data['credits']
    if 'referral_code' in data:
        user.referral_code = data['referral_code']
    if 'verified_status' in data:
        user.verified_status = data['verified_status']

    db.session.commit()
    return jsonify({'message': 'Profile updated successfully'}), 200

if __name__ == '__main__':
    app.run(debug=True)